import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { ChevronDown, Star, Users, Award, Clock } from 'lucide-react';
import { getMenuItems, getReviews } from '../lib/supabase';
import { useCart } from '../lib/CartContext';
import toast from 'react-hot-toast';
import './Home.css';

const HERO_SLIDES = [
  {
    bg: 'https://images.unsplash.com/photo-1547592180-85f173990554?w=1600&q=80',
    tag: 'Signature Dish',
    title: 'Ohn No Khao Swe',
    sub: "Burma's iconic coconut chicken noodle soup",
  },
  {
    bg: 'https://images.unsplash.com/photo-1569050467447-ce54b3bbc37d?w=1600&q=80',
    tag: 'Fresh Daily',
    title: 'Laphet Thoke',
    sub: 'The legendary Burmese tea leaf salad',
  },
  {
    bg: 'https://images.unsplash.com/photo-1414235077428-338989a2e8c0?w=1600&q=80',
    tag: 'Fine Dining',
    title: 'An Authentic Experience',
    sub: 'Warm hospitality & soulful flavours from Yangon',
  },
];

const STATS = [
  { icon: <Star size={22} />,  label: 'Average Rating', value: '4.9' },
  { icon: <Users size={22} />, label: 'Happy Guests',    value: '12K+' },
  { icon: <Award size={22} />, label: 'Years of Craft',  value: '15+' },
  { icon: <Clock size={22} />, label: 'Years in Bangkok',value: '8' },
];

export default function Home() {
  const [slide, setSlide]         = useState(0);
  const [featured, setFeatured]   = useState([]);
  const [reviews, setReviews]     = useState([]);
  const { dispatch }              = useCart();

  useEffect(() => {
    const t = setInterval(() => setSlide(s => (s + 1) % HERO_SLIDES.length), 5000);
    return () => clearInterval(t);
  }, []);

  useEffect(() => {
    getMenuItems().then(({ data }) => {
      if (data) setFeatured(data.slice(0, 6));
    });
    getReviews().then(({ data }) => {
      if (data) setReviews(data.slice(0, 3));
    });
  }, []);

  const addToCart = (item) => {
    dispatch({ type: 'ADD_ITEM', item });
    toast.success(`${item.name} added to cart!`, {
      style: { background: '#FAF6EE', color: '#1E1A14', border: '1px solid #E8A84A' },
      iconTheme: { primary: '#C27A2A', secondary: '#fff' },
    });
  };

  const renderStars = (n) =>
    Array.from({ length: 5 }, (_, i) => (
      <span key={i} className={i < n ? 'star-filled' : 'star-empty'}>★</span>
    ));

  return (
    <div className="home">
      {/* ── Hero ── */}
      <section className="hero">
        {HERO_SLIDES.map((s, i) => (
          <div
            key={i}
            className={`hero__slide ${i === slide ? 'hero__slide--active' : ''}`}
            style={{ backgroundImage: `url(${s.bg})` }}
          />
        ))}
        <div className="hero__overlay" />
        <div className="hero__content container">
          <span className="hero__tag">{HERO_SLIDES[slide].tag}</span>
          <h1 className="hero__title">{HERO_SLIDES[slide].title}</h1>
          <p className="hero__sub">{HERO_SLIDES[slide].sub}</p>
          <div className="hero__actions">
            <Link to="/menu" className="btn btn-primary">Explore Menu</Link>
            <Link to="/reservation" className="btn hero__btn-ghost">Book a Table</Link>
          </div>
        </div>
        {/* Slide dots */}
        <div className="hero__dots">
          {HERO_SLIDES.map((_, i) => (
            <button
              key={i}
              className={`hero__dot ${i === slide ? 'hero__dot--active' : ''}`}
              onClick={() => setSlide(i)}
              aria-label={`Slide ${i + 1}`}
            />
          ))}
        </div>
        <a href="#story" className="hero__scroll-hint">
          <ChevronDown size={20} />
        </a>
      </section>

      {/* ── Stats bar ── */}
      <div className="stats-bar">
        <div className="container stats-bar__inner">
          {STATS.map(({ icon, label, value }) => (
            <div key={label} className="stats-bar__item">
              <span className="stats-bar__icon">{icon}</span>
              <div>
                <div className="stats-bar__value">{value}</div>
                <div className="stats-bar__label">{label}</div>
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* ── Story teaser ── */}
      <section id="story" className="page-section">
        <div className="container home__story">
          <div className="home__story-img">
            <img
              src="https://images.unsplash.com/photo-1555396273-367ea4eb4db5?w=700&q=80"
              alt="Our restaurant interior"
            />
            <div className="home__story-badge">
              <span className="home__story-badge-year">Est.</span>
              <span className="home__story-badge-num">2009</span>
            </div>
          </div>
          <div className="home__story-text">
            <span className="section-label">Our Heritage</span>
            <h2 className="section-title">A Taste of Yangon<br /><em>in the Heart of Bangkok</em></h2>
            <p className="section-subtitle">
              BurmeseBites was born from a deep love of Myanmar's vibrant food culture. 
              Our recipes have been passed down through generations — each curry, each salad, 
              each bowl of noodles carries the warmth of a Burmese grandmother's kitchen.
            </p>
            <div className="home__story-quote">
              <span className="home__story-quote-mark">"</span>
              <p>Food is the memory that travels furthest. Every dish we serve is a bridge between two worlds.</p>
              <cite>— Daw Mya, Founder</cite>
            </div>
            <Link to="/about" className="btn btn-outline">Read Our Full Story →</Link>
          </div>
        </div>
      </section>

      {/* ── Featured Dishes ── */}
      <section className="page-section-alt">
        <div className="container">
          <div className="home__section-head">
            <div>
              <span className="section-label">Taste the Tradition</span>
              <h2 className="section-title">Chef's Selections</h2>
            </div>
            <Link to="/menu" className="btn btn-outline">View Full Menu</Link>
          </div>
          <div className="home__dishes">
            {featured.map(item => (
              <div key={item.id} className="dish-card">
                <div className="dish-card__img-wrap">
                  <img
                    src={`https://images.unsplash.com/photo-${
                      ['1547592180-85f173990554','1569050467447-ce54b3bbc37d','1514190051997-0f6f39ca5cde',
                       '1579684947550-22e945225d9a','1585032226651-759b368d7246','1559339352-11d035aa65de'][
                        featured.indexOf(item) % 6
                      ]
                    }?w=500&q=75`}
                    alt={item.name}
                    loading="lazy"
                  />
                  <div className="dish-card__overlay">
                    <button className="btn btn-primary dish-card__add" onClick={() => addToCart(item)}>
                      Add to Order
                    </button>
                  </div>
                  <div className="dish-card__badges">
                    {item.is_vegetarian && <span className="badge badge-veg">Veg</span>}
                    {item.spicy_level > 0 && (
                      <span className="badge badge-spicy">
                        {'🌶'.repeat(item.spicy_level)}
                      </span>
                    )}
                  </div>
                </div>
                <div className="dish-card__body">
                  <span className="dish-card__category">{item.category}</span>
                  <h3 className="dish-card__name">{item.name}</h3>
                  <p className="dish-card__desc">{item.description}</p>
                  <div className="dish-card__footer">
                    <span className="dish-card__price">${item.price.toFixed(2)}</span>
                    <button onClick={() => addToCart(item)} className="dish-card__add-sm">+</button>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* ── Reviews teaser ── */}
      {reviews.length > 0 && (
        <section className="page-section">
          <div className="container">
            <div className="home__section-head">
              <div>
                <span className="section-label">What Guests Say</span>
                <h2 className="section-title">Heartfelt Reviews</h2>
              </div>
              <Link to="/reviews" className="btn btn-outline">All Reviews</Link>
            </div>
            <div className="home__reviews">
              {reviews.map(r => (
                <div key={r.id} className="review-card">
                  <div className="stars">{renderStars(r.rating)}</div>
                  <p className="review-card__text">"{r.comment}"</p>
                  <div className="review-card__author">
                    <div className="review-card__avatar">
                      {r.name.charAt(0)}
                    </div>
                    <span>{r.name}</span>
                  </div>
                </div>
              ))}
            </div>
          </div>
        </section>
      )}

      {/* ── CTA Banner ── */}
      <section className="cta-banner">
        <div className="cta-banner__bg" />
        <div className="container cta-banner__content">
          <span className="section-label" style={{ color: '#E8A84A' }}>Join Us Tonight</span>
          <h2 className="cta-banner__title">Ready for a Burmese Feast?</h2>
          <p className="cta-banner__sub">Book your table or order for delivery — your taste of Myanmar awaits.</p>
          <div className="cta-banner__actions">
            <Link to="/reservation" className="btn btn-primary">Reserve a Table</Link>
            <Link to="/menu" className="btn cta-banner__btn-ghost">Order Online</Link>
          </div>
        </div>
      </section>
    </div>
  );
}
